<?php namespace App\Models; use App\Enums\AssetStatus;use Illuminate\Database\Eloquent\Factories\HasFactory;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Relations\HasMany;
class Asset extends Model{use HasFactory; protected $fillable=['code','name','category','location','manufacturer','model','serial_number','purchase_date','status','description']; protected function casts():array{return ['purchase_date'=>'date','status'=>AssetStatus::class];} public function workOrders():HasMany{return $this->hasMany(WorkOrder::class);} public function preventiveMaintenances():HasMany{return $this->hasMany(PreventiveMaintenance::class);}}
